async function loadScroller(){function e(){c&&(document.body.scrollTop>20||document.documentElement.scrollTop>20?c.style.display="block":c.style.display="none")}const o=document.querySelectorAll(".header-header-nav-dropdown-toggle");window.innerWidth<=768&&o.forEach(e=>{e.addEventListener("click",function(e){e.preventDefault(),this.closest(".header-nav-dropdown").classList.toggle("active")})});const t=await fetch("/assets/components/scroller.html"),n=await t.text(),l=document.getElementById("scroller-placeholder");l.innerHTML=n;let c=document.getElementById("scroller-button");window.onscroll=function(){e()}}function topFunction(){document.body.scrollTop=0,document.documentElement.scrollTop=0}document.addEventListener("DOMContentLoaded",loadScroller);